	(
		crqfc_id
		, member_id
		, crqfc_nm
		, grad
		, acqdt
		, athrz_instt
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{crqfcId}
		, #{memberId}
		, #{crqfcNm}
		, #{grad}
		, #{acqdt}
		, #{athrzInstt}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptCrqfcDao.update */
update uspt_crqfc
set
	crqfc_nm		= #{crqfcNm}
	, grad			= #{grad}
	, acqdt			= #{acqdt}
	, athrz_instt	= #{athrzInstt}
	, updater_id	= #{updaterId}
	, updated_dt	= #{updatedDt}
where
	member_id = #{memberId}
	and crqfc_id = #{crqfcId}

